package com.pqc.core.entity;
import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime;
@Entity @Table(name="marketing_banners") @Data @Builder @NoArgsConstructor @AllArgsConstructor public class MarketingBanner {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private String title; private String subtitle; private String imageUrl; private String deeplink; @Enumerated(EnumType.STRING) @Column(nullable=false) private BannerPlacement placement; @Builder.Default @Column(nullable=false) private boolean active=true; private LocalDateTime startsAt; private LocalDateTime endsAt; private LocalDateTime createdAt; private LocalDateTime updatedAt; @PrePersist void create(){createdAt=updatedAt=LocalDateTime.now();} @PreUpdate void update(){updatedAt=LocalDateTime.now();}}
